import boto3
from botocore.exceptions import NoCredentialsError
import os
from PIL import Image
from io import BytesIO
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from urllib.parse import urlparse

# AWS S3 and EC2 credentials
AWS_ACCESS_KEY_ID = 'YOUR_AWS_ACCESS_KEY_ID'
AWS_SECRET_ACCESS_KEY = 'YOUR_AWS_SECRET_ACCESS_KEY'

s3 = boto3.client('s3', aws_access_key_id=AWS_ACCESS_KEY_ID,
                      aws_secret_access_key=AWS_SECRET_ACCESS_KEY)

def validate_url(url):
    parsed_url = urlparse(url)
    if parsed_url.netloc in ['127.0.0.1', '192.168.*', '10.*']:
        return False
    return True

def get_screenshot(url, bucket_name):
    try:
        # Validate URL against allowlist
        if not validate_url(url):
            return None
        
        # Set up headless Chrome
        chrome_options = Options()
        chrome_options.add_argument('--headless')
        driver = webdriver.Chrome(options=chrome_options)
        
        # Navigate to the URL and capture screenshot
        driver.get(url)
        screenshot = driver.get_screenshot_as_png()
        
        # Close the browser
        driver.quit()
        
        # Save screenshot to S3
        s3.put_object(Body=screenshot, Bucket=bucket_name, Key=url.split('/')[-1] + '.png')
        
        return url.split('/')[-1] + '.png'
    
    except Exception as e:
        print(f"Error: {e}")
        return None

def lambda_handler(event, context):
    url = event['url']
    bucket_name = 'your-bucket-name'
    
    screenshot_url = get_screenshot(url, bucket_name)
    
    if screenshot_url:
        return {
            'statusCode': 200,
            'body': f'Screenshot saved to S3: {screenshot_url}'
        }
    else:
        return {
            'statusCode': 400,
            'body': 'Invalid URL'
        }

if __name__ == '__main__':
    # Test the function
    url = 'http://example.com'
    print(lambda_handler({'url': url}, None))